import { useEffect, useState } from "react";
import { Player } from "../../objects/player";
import { GetPlayerGameStats } from "../../services/game-stat-service";
import { GameStat } from "../../objects/game-stat";
import { GetTotalGames } from "../../utils/game-stats-util";

interface playerProps{
    player : Player
}

const PlayerCard = (playerProps : playerProps) => {     

    const [gameStats, setGameStats] = useState<GameStat[] | null>(null);

    useEffect(() => {
        GetPlayerGameStats(playerProps.player.id).then(players => setGameStats(players));
    }, []);

    const totalGames = GetTotalGames({gameStats : gameStats});

    return(   
        <div className="col-sm-3">
            <div className="card">
                <div className="card-body">
                    <h5 className="card-title">{playerProps.player.firstname} {playerProps.player.surname} </h5>   
                    
                </div>
            </div>
        </div>        
    )
}
export default PlayerCard;
